import React, { useState, useEffect, useCallback } from 'react';
import {
  CalendarDays, Plus, Check, X, Clock, AlertCircle,
  Send, BarChart2, Calendar, Edit3, Users, Settings,
  RefreshCw, ArrowRightLeft, Shield
} from 'lucide-react';
import toast from 'react-hot-toast';
import { leaveAPI } from '../../api/services';
import { Modal, Badge, SkeletonCard, InlineSpinner } from '../../components/common';
import { useAuth } from '../../context/AuthContext';

// ─── HELPERS ─────────────────────────────────────────────────────────────────
const getErrMsg = (err) => {
  const d = err.response?.data;
  return d?.error?.message || d?.message || err.message || 'An error occurred';
};

const toArr = (r) => {
  const d = r?.data?.data || r?.data || r || [];
  return Array.isArray(d) ? d : (d.requests || d.items || []);
};

const normStatus = s => (s || '').toUpperCase().replace(/_/g, '');

const STATUS_LABEL = {
  SUBMITTED: 'Submitted', PENDING_MANAGER: 'Pending Approval',
  APPROVED: 'Approved', REJECTED: 'Rejected', CANCELLED: 'Cancelled',
};

// ─── UI COMPONENTS ───────────────────────────────────────────────────────────
function RequestRow({ req, onAction, onOverrideClick, isManager, isHR }) {
  const [acting, setActing] = useState('');
  const status = req.Status || req.status || 'SUBMITTED';
  const id = req.LeaveRequestID || req.id;
  const isFinal = ['APPROVED', 'REJECTED', 'CANCELLED'].includes(normStatus(status));

  const act = async (action) => {
    setActing(action);
    try { await onAction(id, action); } finally { setActing(''); }
  };

  return (
    <tr>
      <td>
        <div style={{ fontWeight: 600 }}>{req.LeaveType?.LeaveTypeName || req.LeaveTypeName || 'Leave'}</div>
        <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>{req.Reason || req.reason || 'No reason provided'}</div>
      </td>
      {/* ── SHOW EMPLOYEE NAME FOR SUPERVISORS ── */}
      {isManager && (
        <td>
          <div style={{ fontWeight: 600 }}>{req.Employee?.FullName || req.employeeName || 'Unknown Employee'}</div>
          <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)' }}>{req.Employee?.EmployeeCode}</div>
        </td>
      )}
      <td>{new Date(req.StartDate || req.startDate).toLocaleDateString()} → {new Date(req.EndDate || req.endDate).toLocaleDateString()}</td>
      <td style={{ fontWeight: 600 }}>{req.TotalDays ?? '—'}</td>
      <td><Badge status={status}>{STATUS_LABEL[status] || status}</Badge></td>
      <td>
        <div style={{ display: 'flex', gap: 6 }}>
          {/* ── APPROVAL BUTTONS FOR SUPERVISOR ── */}
          {isManager && !isFinal && (
            <>
              <button className="btn btn-success btn-sm" onClick={() => act('approve')} disabled={!!acting}>
                {acting === 'approve' ? <InlineSpinner /> : 'Approve'}
              </button>
              <button className="btn btn-danger btn-sm" onClick={() => act('reject')} disabled={!!acting}>
                {acting === 'reject' ? <InlineSpinner /> : 'Reject'}
              </button>
            </>
          )}
          {isHR && isFinal && normStatus(status) !== 'CANCELLED' && (
            <button className="btn btn-ghost btn-sm" onClick={() => onOverrideClick(req)}><Shield size={13}/> Override</button>
          )}
          {!isManager && !isFinal && (
            <button className="btn btn-ghost btn-sm" onClick={() => act('cancel')}>Cancel</button>
          )}
        </div>
      </td>
    </tr>
  );
}

// ─── MAIN PAGE ───────────────────────────────────────────────────────────────
export default function LeavePage() {
  const { user } = useAuth();

  // ── 1. AUTHORITY LOGIC ──
  const posId = parseInt(user?.PositionID || user?.positionId, 10);
  const roleStr = (user?.role || user?.Role || '').toUpperCase();
  const userEmail = (user?.email || user?.Email || '').toLowerCase();

  // Supervisor Check: Mona (2), HR Manager (1), or Admin
  const isManager = 
    roleStr.includes('MANAGER') || roleStr.includes('HR') || roleStr.includes('ADMIN') || 
    posId === 1 || posId === 2 || userEmail === 'mona@university.edu';

  // Admin/HR Check
  const isHR = roleStr.includes('HR') || roleStr.includes('ADMIN') || posId === 1;

  const [tab, setTab] = useState('dashboard');
  const [balances, setBalances] = useState([]);
  const [myRequests, setMyReqs] = useState([]);
  const [allRequests, setAll] = useState([]);
  const [leaveTypes, setTypes] = useState([]);
  const [loading, setLoading] = useState({ bal: true, req: true, all: true });

  // ── 2. DATA LOADING ──
  const loadData = useCallback(() => {
    setLoading(prev => ({ ...prev, bal: true, req: true }));
    leaveAPI.getMyBalances().then(r => setBalances(toArr(r))).finally(() => setLoading(prev => ({ ...prev, bal: false })));
    leaveAPI.getMyRequests().then(r => setMyReqs(toArr(r))).finally(() => setLoading(prev => ({ ...prev, req: false })));

    if (isManager) {
      setLoading(prev => ({ ...prev, all: true }));
      // 🔥 KEY CHANGE: Mona calls Team Inbox, HR calls Company List
      const fetchCall = isHR ? leaveAPI.listAll() : leaveAPI.getManagerInbox();
      fetchCall
        .then(r => {
          const data = toArr(r);
          console.log("📦 Loaded Management Data:", data);
          setAll(data);
        })
        .finally(() => setLoading(prev => ({ ...prev, all: false })));
    }
  }, [isManager, isHR]);

  useEffect(() => { loadData(); }, [loadData]);

  // ── 3. TABS CONFIG ──
  const TABS = [
    { id: 'dashboard', label: 'Dashboard', icon: BarChart2 },
    { id: 'history', label: 'My History', icon: Clock },
    ...(isManager ? [{ id: 'all', label: isHR ? 'Company Requests' : 'Team Inbox', icon: Users }] : []),
    ...(isHR ? [{ id: 'settings', label: 'Settings', icon: Settings }] : []),
  ];

  const handleAction = async (id, action, reason) => {
    try {
      if (action === 'approve') await leaveAPI.approveReject(id, { decision: 'APPROVED' });
      else if (action === 'reject') await leaveAPI.approveReject(id, { decision: 'REJECTED', comments: reason });
      else if (action === 'cancel') await leaveAPI.cancel(id, { CancelReason: 'User cancelled' });
      toast.success(`Request ${action}ed successfully`);
      loadData();
    } catch (err) { toast.error(getErrMsg(err)); }
  };

  return (
    <div className="page-container">
      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem' }}>
        <div><h1>Leave Management</h1><p>Welcome, <strong>{user?.FullName || 'User'}</strong></p></div>
        <button className="btn btn-primary" onClick={() => toast.success("Submit functionality active")}><Plus size={18} /> New Request</button>
      </div>

      <div className="tabs" style={{ padding: '0 1rem' }}>
        {TABS.map(({ id, label, icon: Icon }) => (
          <button key={id} className={`tab-btn ${tab === id ? 'active' : ''}`} onClick={() => setTab(id)}>
            <Icon size={14} style={{ marginRight: 6 }} />{label}
          </button>
        ))}
      </div>

      <div style={{ padding: '1rem' }}>
        {tab === 'dashboard' && (
          <div className="grid-4">
            {balances.length === 0 ? <p>No balances available</p> : balances.map((b, i) => (
              <div key={i} className="card p-4 shadow-sm border-0">
                <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>{b.LeaveTypeName}</div>
                <div style={{ fontSize: '1.5rem', fontWeight: 700, color: 'var(--primary)' }}>{b.RemainingDays} <span style={{fontSize: '0.9rem', fontWeight: 400}}>Days</span></div>
              </div>
            ))}
          </div>
        )}

        {tab === 'all' && (
          <div className="card shadow-sm border-0">
            <div className="table-wrap">
              <table>
                <thead>
                  <tr><th>Type & Reason</th>{isManager && <th>Employee</th>}<th>Period</th><th>Days</th><th>Status</th><th>Actions</th></tr>
                </thead>
                <tbody>
                  {allRequests.map((req, i) => (
                    <RequestRow key={i} req={req} onAction={handleAction} isManager={true} isHR={isHR} />
                  ))}
                </tbody>
              </table>
              {allRequests.length === 0 && (
                <div style={{ padding: 60, textAlign: 'center' }}>
                   <Users size={40} style={{ opacity: 0.1, marginBottom: 12 }} />
                   <p style={{ color: 'var(--text-muted)' }}>No pending requests from your team.</p>
                </div>
              )}
            </div>
          </div>
        )}

        {tab === 'history' && (
          <div className="card shadow-sm border-0">
            <div className="table-wrap">
              <table>
                <thead><tr><th>Type</th><th>Period</th><th>Days</th><th>Status</th><th>Actions</th></tr></thead>
                <tbody>
                  {myRequests.map((req, i) => (
                    <RequestRow key={i} req={req} onAction={handleAction} isManager={false} />
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
